INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('pukao-6f0ba476-moex-00279', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-111-a7c7609b', 'sub-pukao-6f0ba476-02', NULL, 'single_choice', '甲為婦產科醫師，受託為知名女星乙進行人工生殖手術；手術完畢後，某日甲與友人丙閒聊時透 漏女星乙相關就診之事，熟料丙嗣後竟將該事洩漏給記者丁，丁遂大肆報導此事，造成女星乙不 堪其擾、身心俱疲。下列敘述，何者正確？', '["因甲之給付義務乃為乙實施人工生殖手術，甲既已完成手術，即屬已履行其債務，故甲對乙不負 債務不履行之責任", "丙非甲之債務履行輔助人，故丙向丁洩漏乙因人工生殖就醫之事而丁加以報導，雖造成乙身心受 損，甲亦無須負債務不履行責任", "因丁大肆報導乙進行人工生殖手術之事，乃侵害乙之隱私，故乙得向丁請求侵權行為之損害賠償", "乙僅得向丁請求侵權行為之損害賠償，而不得另向甲請求不完全給付之損害賠償"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:46+00:00", "source_pdf_sha1": "8643edec57b1", "answer_pdf_sha1": "2783db52ca84", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "414", "s": "1105", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00280', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-111-a7c7609b', 'sub-pukao-6f0ba476-02', NULL, 'single_choice', '下列何者為民法規定之定著物？', '["木瓜樹", "供展覽使用之貨櫃屋", "公園之涼亭", "跨年晚會搭建之舞臺"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:46+00:00", "source_pdf_sha1": "8643edec57b1", "answer_pdf_sha1": "2783db52ca84", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "414", "s": "1105", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00281', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-111-a7c7609b', 'sub-pukao-6f0ba476-02', NULL, 'single_choice', '甲無權占有他人土地A，並在其上蓋一違章工廠B，並將A、B出賣並移轉乙占有。下列敘述， 何者正確？', '["甲得移轉登記B之所有權予乙", "B遭丙無權占有，乙不得享有占有之保護", "甲如符合時效取得要件，亦得主張時效取得A之地上權", "甲得以變更起造人名義之方式，移轉B之所有權予乙"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:46+00:00", "source_pdf_sha1": "8643edec57b1", "answer_pdf_sha1": "2783db52ca84", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "414", "s": "1105", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00282', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-111-a7c7609b', 'sub-pukao-6f0ba476-02', NULL, 'single_choice', '下列關於物上請求權之敘述，何者錯誤？', '["所有人對於無權占有或侵奪所有物者，得請求返還之", "所有人對於占有以外之方法妨害其所有權者，得請求除去之", "所有人對於有妨害其所有權之虞者，得請求防止之", "物上請求權，乃所有權人排除他人干涉之保護機制，於所有權以外之其他物權不適用之"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:46+00:00", "source_pdf_sha1": "8643edec57b1", "answer_pdf_sha1": "2783db52ca84", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "414", "s": "1105", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00283', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-111-a7c7609b', 'sub-pukao-6f0ba476-02', NULL, 'single_choice', '下列何者非屬普通抵押權不可分性之內容？', '["抵押之不動產如經分割或讓與其一部，其抵押權不因此而受影響", "以抵押權擔保之債權，如經分割或讓與其一部，其抵押權不因此而受影響", "擔保一債權之數不動產，而以其一部讓與他人者，其抵押權不因此而受影響", "抵押權不得由債權分離而為讓與，或為其他債權之擔保"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:46+00:00", "source_pdf_sha1": "8643edec57b1", "answer_pdf_sha1": "2783db52ca84", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "414", "s": "1105", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00284', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-111-a7c7609b', 'sub-pukao-6f0ba476-02', NULL, 'single_choice', '甲合法收養乙時，乙已經有成年子女丙，及未成年子女丁與戊，丁已婚。法院認可甲乙收養關係 時，僅丁依法表示同意。甲之妹妹為庚，與庚因收養而成立之旁系血親關係者為誰？', '["乙丙丁戊", "僅乙丁戊", "僅乙丁", "僅乙"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:46+00:00", "source_pdf_sha1": "8643edec57b1", "answer_pdf_sha1": "2783db52ca84", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "414", "s": "1105", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00285', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-111-a7c7609b', 'sub-pukao-6f0ba476-02', NULL, 'single_choice', '甲夫乙妻適用法定夫妻財產制。甲乙離婚時，甲有現存婚後財產新臺幣（下同）1,000萬元存款， 其中有200萬元為甲車禍收到肇事者丙賠償之慰撫金。乙有現存婚後財產2,000萬元，包含繼承 自父親丁之房屋，其價值1,000萬元。下列關於雙方剩餘財產差額分配之敘述，何者正確？', '["甲得向乙請求200萬元", "乙得向甲請求200萬元", "甲得向乙請求100萬元", "乙得向甲請求100萬元"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:46+00:00", "source_pdf_sha1": "8643edec57b1", "answer_pdf_sha1": "2783db52ca84", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "414", "s": "1105", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00286', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-111-a7c7609b', 'sub-pukao-6f0ba476-02', NULL, 'single_choice', '被繼承人甲生前欠國稅局稅金新臺幣（下同）1,000萬元；被繼承人甲生前又向債權人乙借貸1,000 萬元，甲乙間之法律關係為一般債權債務關係，被繼承人甲死亡時，留下遺產1,200萬元，繼承人 丙依法開具遺產清冊陳報法院，惟繼承人丙雖係成年但不諳法律，故先清償甲生前向債權人乙借貸 1,000萬元，再以200萬元清償被繼承人甲生前欠國稅局稅金。國稅局是否依法得向乙請求金額？', '["依民法不得向乙請求任何金額", "依民法第1161條第2項不當受領規定，得向乙請求800萬元", "依民法第179條不當得利規定，得向乙請求800萬元", "依民法第1162條之2第4項不當受領規定，得向乙請求800萬元"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:46+00:00", "source_pdf_sha1": "8643edec57b1", "answer_pdf_sha1": "2783db52ca84", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "414", "s": "1105", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00287', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-111-a7c7609b', 'sub-pukao-6f0ba476-02', NULL, 'single_choice', '下列何種情形，非屬民法第184條第2項：「違反保護他人之法律，致生損害於他人者，負賠償 責任」之案型？', '["甲違反道路交通管理處罰條例規定，將甲自己之A車交予無駕照之乙駕駛，乙開A車撞傷丙", "雇主甲違反勞工保險條例規定，未為勞工乙加入勞工保險，乙因而受有損失", "常務董事甲違反民法第35條規定，未為法人向法院聲請宣告破產，致法人之債權人乙受有損害", "民營銀行行員甲未依銀行內部規定，辦理擔保品之鑑價，致銀行不能受足額清償之危險"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:46+00:00", "source_pdf_sha1": "8643edec57b1", "answer_pdf_sha1": "2783db52ca84", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "414", "s": "1105", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00288', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-111-e38ac4c6', 'sub-pukao-6f0ba476-03', NULL, 'essay', '我國對於溢繳稅款之退稅規定為何？又行為人明知無納稅義務，違反稅
